(function(){function getComponentsArray(component){let cleanedComp=component.trim().substr(5,component.length-10);return cleanedComp.split('|')}
    const componentToHtmlTable=components=>{let table=['<table class="image-accessory"><tr>'];const component=getComponentsArray(components);table.push('<td>'+component[0]+'</td>');table.push('<td>'+component[1]+'</td>');table.push('</tr></table>');return table.join('')};const after=html=>{let imageStamps=html.match(/&lt;:([\S\s]*?):&gt;/g);if(!imageStamps)return html;let tableComponent;for(let i=0;i<imageStamps.length;i++){tableComponent=componentToHtmlTable(imageStamps[i]);html=html.replace(imageStamps[i],tableComponent)}
        return html};const imageParser=hook=>{hook.afterEach(html=>after(html))};$docsify.plugins=[].concat(imageParser,$docsify.plugins)}())